/**
 * BSM Knowledge Embedding Script
 *
 * Reads pre-extracted knowledge from worker/data/knowledge.json (generated by
 * scripts/extract-scenarios.js) and embeds everything into Cloudflare Vectorize.
 *
 * Called from worker route: POST /admin/embed-knowledge
 * Requires: env.AI (Workers AI) and env.VECTORIZE (Vectorize index)
 *
 * Build step: node scripts/extract-scenarios.js → worker/data/knowledge.json
 */

import knowledge from "../data/knowledge.json";

// ─── Helpers ─────────────────────────────────────────────────────────────────

function batch(arr, size) {
  const batches = [];
  for (let i = 0; i < arr.length; i += size) batches.push(arr.slice(i, i + size));
  return batches;
}

/** Split text into ~500-token chunks (~2000 chars) with overlap */
function chunkText(text, maxChars = 2000, overlapChars = 200) {
  if (text.length <= maxChars) return [text];
  const chunks = [];
  let start = 0;
  while (start < text.length) {
    const end = Math.min(start + maxChars, text.length);
    chunks.push(text.slice(start, end));
    if (end >= text.length) break;
    start = end - overlapChars;
  }
  return chunks;
}

// ─── Section builders ────────────────────────────────────────────────────────

/** SECTION 1: Build scenario vectors */
function buildScenarioEntries() {
  return knowledge.scenarios.map(s => {
    const text = `${s.title}. ${s.description} Options: ${s.options.join(" | ")}. Best: ${s.options[s.best]}. Concept: ${s.concept}`;
    return {
      id: `scenario_${s.position}_${s.id}`,
      text,
      metadata: {
        type: "scenario",
        position: s.position,
        concept: s.conceptTag || s.concept,
        difficulty: s.diff,
        scenarioId: s.id,
        title: s.title
      }
    };
  });
}

/** SECTION 2: Build knowledge map vectors */
function buildMapEntries() {
  const entries = [];
  for (const [name, content] of Object.entries(knowledge.knowledgeMaps)) {
    const positions = knowledge.mapRelevance?.[name] || [];
    const chunks = chunkText(content, 2000, 200);
    chunks.forEach((chunk, i) => {
      entries.push({
        id: `map_${name}${chunks.length > 1 ? `_part${i + 1}` : ""}`,
        text: `Knowledge Map: ${name.replace(/_/g, " ")}\n\n${chunk}`,
        metadata: {
          type: "map",
          name,
          positions: positions.join(",")
        }
      });
    });
  }
  return entries;
}

/** SECTION 3: Build position principle vectors */
function buildPrincipleEntries() {
  const entries = [];
  for (const [position, text] of Object.entries(knowledge.posPrinciples)) {
    const chunks = chunkText(text, 2000, 200);
    chunks.forEach((chunk, i) => {
      entries.push({
        id: `principle_${position}${chunks.length > 1 ? `_part${i + 1}` : ""}`,
        text: `Position Principles: ${position}\n\n${chunk}`,
        metadata: { type: "principle", position }
      });
    });
  }
  // Also embed condensed AI principles
  for (const [position, text] of Object.entries(knowledge.aiPosPrinciples)) {
    entries.push({
      id: `ai_principle_${position}`,
      text: `AI Position Principles (condensed): ${position}\n\n${text}`,
      metadata: { type: "principle", position, variant: "condensed" }
    });
  }
  return entries;
}

/** SECTION 4: Build Scenario Bible vectors */
function buildBibleEntries() {
  if (!knowledge.scenarioBible) return [];
  const entries = [];
  const parts = knowledge.scenarioBible.split(/(?=^## )/m);
  for (let i = 0; i < parts.length; i++) {
    const part = parts[i].trim();
    if (!part) continue;
    const headerMatch = part.match(/^##\s*(.+)/);
    const section = headerMatch ? headerMatch[1].trim() : `section_${i}`;
    const chunks = chunkText(part, 2000, 200);
    chunks.forEach((chunk, j) => {
      entries.push({
        id: `bible_${i}_${section.toLowerCase().replace(/[^a-z0-9]+/g, "_").slice(0, 40)}${chunks.length > 1 ? `_part${j + 1}` : ""}`,
        text: `Scenario Bible: ${section}\n\n${chunk}`,
        metadata: { type: "bible", section }
      });
    });
  }
  return entries;
}

/** SECTION 5: Build BRAIN data vectors */
function buildBrainEntries() {
  const entries = [];
  const stats = knowledge.brainStats;

  // RE24 — natural language descriptions
  if (stats.RE24) {
    const runnerLabels = {
      "---": "bases empty", "1--": "runner on 1st", "-2-": "runner on 2nd",
      "--3": "runner on 3rd", "12-": "runners on 1st and 2nd", "1-3": "runners on 1st and 3rd",
      "-23": "runners on 2nd and 3rd", "123": "bases loaded"
    };
    const lines = [];
    for (const [key, vals] of Object.entries(stats.RE24)) {
      const label = runnerLabels[key] || key;
      lines.push(`${label}: ${vals[0]} expected runs (0 outs), ${vals[1]} (1 out), ${vals[2]} (2 outs)`);
    }
    entries.push({
      id: "brain_re24",
      text: `Run Expectancy Matrix (RE24) — FanGraphs 2015-2024 MLB averages:\n\n${lines.join("\n")}`,
      metadata: { type: "brain", dataType: "RE24" }
    });
  }

  // Count data
  if (stats.countData) {
    const lines = [];
    for (const [count, data] of Object.entries(stats.countData)) {
      lines.push(`Count ${count} (${data.label || ""}): BA ${data.ba}, OBP ${data.obp}, SLG ${data.slg}, edge=${data.edge}`);
    }
    entries.push({
      id: "brain_count_data",
      text: `Count Leverage Data — batting metrics by count:\n\n${lines.join("\n")}`,
      metadata: { type: "brain", dataType: "countData" }
    });
  }

  // Steal break-even
  if (stats.stealBreakEven) {
    entries.push({
      id: "brain_steal_breakeven",
      text: `Steal Break-Even Rates by outs: 0 outs = ${stats.stealBreakEven["0"] * 100}%, 1 out = ${stats.stealBreakEven["1"] * 100}%, 2 outs = ${stats.stealBreakEven["2"] * 100}%. A stolen base attempt must succeed at this rate or higher to be worthwhile (per RE24). Source: FanGraphs run expectancy.`,
      metadata: { type: "brain", dataType: "stealBreakEven" }
    });
  }

  // Bunt delta
  if (stats.buntDelta) {
    const lines = Object.entries(stats.buntDelta).map(([k, v]) => {
      const [runners, outs] = k.split("_");
      return `${runners} with ${outs} outs: ${v} expected runs change`;
    });
    entries.push({
      id: "brain_bunt_delta",
      text: `Sacrifice Bunt RE24 Cost — how much a bunt costs in expected runs:\n\n${lines.join("\n")}\n\nBunting almost always lowers run expectancy. Exception: weak hitter, late game, need exactly 1 run.`,
      metadata: { type: "brain", dataType: "buntDelta" }
    });
  }

  // TTO effect
  if (stats.ttoEffect) {
    entries.push({
      id: "brain_tto",
      text: `Times Through the Order (TTO) Effect: 1st time = +${stats.ttoEffect[0]} BA points, 2nd time = +${stats.ttoEffect[1]} BA points, 3rd time = +${stats.ttoEffect[2]} BA points. Batters hit significantly better the 3rd time through the order. Source: The Book (Tango/Lichtman/Dolphin), FanGraphs TTO splits 2019-2023.`,
      metadata: { type: "brain", dataType: "ttoEffect" }
    });
  }

  // Concepts graph
  if (knowledge.brainConcepts && Object.keys(knowledge.brainConcepts).length > 0) {
    const lines = Object.entries(knowledge.brainConcepts).map(([tag, c]) =>
      `${tag}: ${c.name} (domain=${c.domain}, diff=${c.diff}, ageMin=${c.ageMin}, prereqs=[${(c.prereqs || []).join(",")}])`
    );
    const chunks = chunkText(lines.join("\n"), 2000, 200);
    chunks.forEach((chunk, i) => {
      entries.push({
        id: `brain_concepts${chunks.length > 1 ? `_part${i + 1}` : ""}`,
        text: `BRAIN Concept Prerequisite Graph:\n\n${chunk}`,
        metadata: { type: "brain", dataType: "concepts" }
      });
    });
  }

  return entries;
}

// ─── Main export ─────────────────────────────────────────────────────────────

/**
 * Embed all BSM knowledge into Vectorize.
 * @param {Object} env - Worker env with AI and VECTORIZE bindings
 * @returns {Object} Summary with counts, timing, and log
 */
export async function embedAllKnowledge(env) {
  const t0 = Date.now();
  const log = [];

  // Build all entries
  log.push("Building entries from knowledge.json...");
  const scenarioEntries = buildScenarioEntries();
  log.push(`  Scenarios: ${scenarioEntries.length}`);
  const mapEntries = buildMapEntries();
  log.push(`  Maps: ${mapEntries.length}`);
  const principleEntries = buildPrincipleEntries();
  log.push(`  Principles: ${principleEntries.length}`);
  const bibleEntries = buildBibleEntries();
  log.push(`  Bible sections: ${bibleEntries.length}`);
  const brainEntries = buildBrainEntries();
  log.push(`  Brain: ${brainEntries.length}`);

  const allEntries = [...scenarioEntries, ...mapEntries, ...principleEntries, ...bibleEntries, ...brainEntries];
  log.push(`\nTotal entries: ${allEntries.length}`);

  // Embed in batches of 50
  const EMBED_BATCH = 50;
  const entryBatches = batch(allEntries, EMBED_BATCH);
  const allVectors = [];

  log.push(`Embedding in ${entryBatches.length} batches...`);

  for (let i = 0; i < entryBatches.length; i++) {
    const eb = entryBatches[i];
    const texts = eb.map(e => e.text.slice(0, 8000));
    try {
      const result = await env.AI.run("@cf/baai/bge-large-en-v1.5", { text: texts });
      if (!result?.data || result.data.length !== texts.length) {
        log.push(`  Batch ${i + 1}: WARNING — got ${result?.data?.length || 0}/${texts.length} embeddings`);
        continue;
      }
      for (let j = 0; j < eb.length; j++) {
        allVectors.push({
          id: eb[j].id,
          values: result.data[j],
          metadata: { ...eb[j].metadata, text: eb[j].text.slice(0, 10000) }
        });
      }
      log.push(`  Batch ${i + 1}/${entryBatches.length}: ${eb.length} embedded`);
    } catch (err) {
      log.push(`  Batch ${i + 1}: ERROR — ${err.message}`);
    }
  }

  // Upsert in batches of 100
  const UPSERT_BATCH = 100;
  const vectorBatches = batch(allVectors, UPSERT_BATCH);
  let totalUpserted = 0;

  log.push(`\nUpserting ${allVectors.length} vectors in ${vectorBatches.length} batches...`);

  for (let i = 0; i < vectorBatches.length; i++) {
    try {
      await env.VECTORIZE.upsert(vectorBatches[i]);
      totalUpserted += vectorBatches[i].length;
      log.push(`  Upsert ${i + 1}/${vectorBatches.length}: ${vectorBatches[i].length} vectors`);
    } catch (err) {
      log.push(`  Upsert ${i + 1}: ERROR — ${err.message}`);
    }
  }

  const elapsed = Date.now() - t0;
  const summary = {
    totalEmbedded: allVectors.length,
    totalUpserted,
    byType: {
      scenario: scenarioEntries.length,
      map: mapEntries.length,
      principle: principleEntries.length,
      bible: bibleEntries.length,
      brain: brainEntries.length
    },
    elapsed,
    log
  };

  log.push(`\nDone in ${elapsed}ms — ${totalUpserted}/${allEntries.length} embedded and stored.`);
  return summary;
}

/**
 * Query Vectorize for relevant knowledge.
 * @param {Object} env - Worker env
 * @param {string} query - Search text
 * @param {number} topK - Number of results (default 3)
 * @param {Object} filter - Metadata filter: { type, position, difficulty }
 * @returns {Array} Matches with text, score, metadata
 */
export async function queryKnowledge(env, query, topK = 3, filter = {}) {
  const embedResult = await env.AI.run("@cf/baai/bge-large-en-v1.5", { text: [query] });
  if (!embedResult?.data?.[0]) throw new Error("Failed to embed query");

  const queryOptions = {
    topK,
    returnMetadata: "all",
    returnValues: false
  };

  // Vectorize filter uses $eq operator syntax
  if (filter && Object.keys(filter).length > 0) {
    const vFilter = {};
    for (const [key, value] of Object.entries(filter)) {
      vFilter[key] = { $eq: value };
    }
    queryOptions.filter = vFilter;
  }

  const results = await env.VECTORIZE.query(embedResult.data[0], queryOptions);

  return (results.matches || []).map(match => ({
    id: match.id,
    score: match.score,
    text: match.metadata?.text || "",
    type: match.metadata?.type || "",
    position: match.metadata?.position || "",
    concept: match.metadata?.concept || "",
    metadata: match.metadata || {}
  }));
}
